// Assign rules to lanes (round-robin for simplicity)
static void getRuleLaneAssignment(uint16_t ruleId, uint8_t* laneIdx, uint16_t* laneRuleIdx) {
    *laneIdx = ruleId % NUM_LANES;
    *laneRuleIdx = ruleId / NUM_LANES;
}

// Load pattern into FPSM via PCIe writes
// writeReg(offset, data) should write a 32-bit value to PCIe register at offset
static void loadPatternIntoFPSM(uint8_t laneIdx, uint16_t ruleId, const uint8_t* pattern, uint8_t len) {
    // Set lane index (offset 16)
    writeReg(16, laneIdx);
    
    // Set pattern length (offset 17)
    writeReg(17, len);
    
    // Set rule ID (offset 18)
    writeReg(18, ruleId);
    
    // Load pattern data in 8 × 32-bit chunks (offsets 19-26)
    uint32_t patternWords[8] = {0};
    memcpy(patternWords, pattern, std::min((int)len, 32));
    
    for (int i = 0; i < 8; i++) {
        writeReg(19 + i, patternWords[i]);
    }
}

// Load all patterns into FPSM
static void loadAllPatterns() {
    printf("Loading %d patterns into %d FPSM lanes...\n", NUM_RULES, NUM_LANES);
    
    // Load ALL patterns, distributing across lanes using round-robin
    for (int i = 0; i < NUM_RULES; i++) {
        const RulePattern& pat = g_patterns[i];
        uint8_t laneIdx;
        uint16_t laneRuleIdx;
        getRuleLaneAssignment(pat.ruleId, &laneIdx, &laneRuleIdx);
        loadPatternIntoFPSM(laneIdx, pat.ruleId, pat.pattern, pat.patternLen);
        
        if ((i + 1) % 50 == 0) {
            printf("  Loaded %d patterns...\n", i + 1);
        }
    }
    
    printf("Pattern loading complete! Loaded %d rules across %d lanes\n", NUM_RULES, NUM_LANES);
}

// Load specific test patterns (Rules 0, 3, 20 for test_packets.pcap)
static void loadTestPatterns() {
    printf("Loading test patterns (Rules 0, 3, 20)...\n");
    
    // Rule 0 -> Lane 0\n    loadPatternIntoFPSM(0, 0, g_patterns[0].pattern, g_patterns[0].patternLen);\n    // Rule 3 -> Lane 1\n    loadPatternIntoFPSM(1, 3, g_patterns[3].pattern, g_patterns[3].patternLen);\n    // Rule 20 -> Lane 2\n    loadPatternIntoFPSM(2, 20, g_patterns[20].pattern, g_patterns[20].patternLen);\n    
    printf("Test patterns loaded!\n");
}
